const body = $input.first().json.body || {};
const action = String(body.action || 'list').trim();
if (!['list','upsert','delete'].includes(action)) {
  return [{ json: { valid: 0, error: 'Неизвестный action' } }];
}
const token = String(body.token || '').trim();
if (!/^[a-f0-9]{64}$/.test(token)) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}
const out = { valid: 1, action, token };
if (action === 'upsert' || action === 'delete') {
  const sid = String(body.session_id || '').trim();
  if (!sid || !/^[a-zA-Z0-9_-]+$/.test(sid)) {
    return [{ json: { valid: 0, error: 'session_id обязательно' } }];
  }
  out.session_id = sid;
  if (action === 'upsert') {
    const name = String(body.name || '').trim().slice(0, 200);
    if (!name) return [{ json: { valid: 0, error: 'name обязательно' } }];
    out.name = name;
    const so = parseInt(body.sort_order, 10);
    out.sort_order = Number.isInteger(so) ? so : 0;
  }
}
return [{ json: out }];

const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id } }];

const items = $input.all().map(i => (i && i.json) || {});
const first = items[0] || {};
if (first.error) {
  return [{ json: { response: 'error', error: String(first.error.message || first.error) } }];
}
const sessions = items.filter(i => i && i.session_id).map(i => ({ session_id: i.session_id, name: i.name, sort_order: i.sort_order }));
return [{ json: { response: 'ok', sessions } }];
